import { NextResponse } from "next/server"

import { requireApiUser } from "@/app/api/_auth"
import { cancelAsaasSubscription } from "@/lib/asaas"
import { getBillingProvider } from "@/lib/billing-provider"
import { prisma } from "@/lib/prisma"
import { stripe } from "@/lib/stripe"

export async function DELETE() {
  const { session, error } = await requireApiUser()
  if (error) return error

  try {
    const configuredProvider = getBillingProvider()
    const user = await prisma.user.findUnique({
      where: { id: session.user.id! },
      select: {
        billingCustomerId: true,
        billingProvider: true,
        billingSubscriptionId: true,
      },
    })

    if (!user?.billingSubscriptionId) {
      return NextResponse.json({ success: false, message: "Nao existe assinatura ativa para cancelar agora." }, { status: 400 })
    }

    const provider = String(user.billingProvider || configuredProvider).toUpperCase()

    if (provider === "STRIPE") {
      if (!stripe) {
        return NextResponse.json({ success: false, message: "Stripe ainda nao foi configurado neste ambiente." }, { status: 500 })
      }

      await stripe.subscriptions.cancel(user.billingSubscriptionId)
    } else {
      await cancelAsaasSubscription(user.billingSubscriptionId)
    }

    const updatedUser = await prisma.user.update({
      where: { id: session.user.id! },
      data: {
        plan: "FREE",
        planStatus: "ACTIVE",
        planActivatedAt: new Date(),
        billingPendingPlan: null,
        billingCheckoutId: null,
        billingSubscriptionId: null,
      },
      select: {
        id: true,
        plan: true,
        planStatus: true,
        billingCustomerId: true,
        billingSubscriptionId: true,
      },
    })

    await prisma.payment.create({
      data: {
        provider,
        type: "SUBSCRIPTION_CANCELED",
        status: "CANCELED",
        customerId: user.billingCustomerId || undefined,
        userId: session.user.id!,
        providerSubscriptionId: user.billingSubscriptionId,
      },
    })

    return NextResponse.json({
      success: true,
      message: "Assinatura cancelada com sucesso. Sua conta voltou para o plano Free.",
      user: updatedUser,
    })
  } catch (cancelError) {
    console.error("ERRO DELETE /api/billing/subscription:", cancelError)
    return NextResponse.json({ success: false, message: "Nao foi possivel cancelar a assinatura agora." }, { status: 500 })
  }
}
